import java.nio.ByteBuffer;
import java.nio.charset.StandardCharsets;
import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Secure code - no buffer overflow vulnerability
        byte[] nameBytes = name.getBytes(StandardCharsets.UTF_8);

        // Ensure that the buffer size matches the input length or adjust accordingly
        ByteBuffer buffer = ByteBuffer.allocate(nameBytes.length);
        buffer.put(nameBytes);

        System.out.println("Hello, " + new String(buffer.array(), StandardCharsets.UTF_8));
    }
}

